(function () {
  'use strict';

  /**
   * Clase AutoComplete - Autocompletado avanzado con búsqueda remota
   * @param {Object} config - Configuración del autocompletado
   * @param {string} config.inputId - ID del input de búsqueda (requerido)
   * @param {string} config.suggestionsId - ID del contenedor de sugerencias (requerido)
   * @param {string} [config.hiddenInputId] - ID del input hidden para guardar el ID seleccionado
   * @param {string} config.apiUrl - URL del endpoint de búsqueda (requerido)
   * @param {string} [config.jwtToken] - Token JWT para autorización
   * @param {number} [config.minChars=3] - Mínimo de caracteres para activar búsqueda
   * @param {string} [config.displayKey='full_name'] - Campo a mostrar en sugerencias
   * @param {string} [config.valueKey='id'] - Campo a guardar como valor seleccionado
   * @param {string} [config.emptyMessage='No se encontraron resultados'] - Mensaje para resultados vacíos
   * @param {number} [config.debounceTime=300] - Tiempo de espera después de escribir (ms)
   */
  class AutoComplete {
    constructor(config) {
      // Validación de configuraciones requeridas
      if (!config || typeof config !== 'object') {
        throw new Error('Se requiere un objeto de configuración');
      }
      console.log(config);
      const required = ['inputId', 'suggestionsId', 'apiUrl'];
      const missing = required.filter(field => !config[field]);
      if (missing.length > 0) {
        throw new Error(`Faltan parámetros requeridos: ${missing.join(', ')}`);
      }

      // Configuración con valores por defecto
      this.config = {
        minChars: 3,
        displayKey: 'full_name',
        valueKey: 'id',
        emptyMessage: 'No se encontraron resultados',
        debounceTime: 300,
        ...config
      };

      // Obtener elementos DOM
      this.input = document.getElementById(this.config.inputId);
      this.suggestionsDiv = document.getElementById(this.config.suggestionsId);
      this.hiddenInput = this.config.hiddenInputId 
        ? document.getElementById(this.config.hiddenInputId) 
        : null;

      // Validar elementos del DOM
      if (!this.input || !this.suggestionsDiv) {
        throw new Error('No se encontraron los elementos del DOM especificados');
      }

      // Estado interno
      this.activeIndex = -1;
      this.currentSuggestions = [];
      this.lastRequest = null;

      // Inicializar eventos
      this.initEvents();
    }

    // Métodos públicos
    initEvents() {
      // Limpiar búsquedas previas al enfocar
      this.input.addEventListener('focus', () => {
        if (this.input.value.length >= this.config.minChars) {
          this.handleInput();
        }
      });

      // Búsqueda con debounce
      this.input.addEventListener('input', this.debounce(() => {
        this.handleInput();
      }, this.config.debounceTime));

      // Navegación con teclado
      this.input.addEventListener('keydown', (e) => this.handleKeydown(e));

      // Cerrar al hacer clic fuera
      document.addEventListener('click', (e) => {
        if (!this.suggestionsDiv.contains(e.target) && e.target !== this.input) {
          this.clearSuggestions();
        }
      });

      // Evento personalizado cuando se selecciona un ítem
      this.input.addEventListener('autocomplete-select', (e) => {
        console.log('Ítem seleccionado:', e.detail);
      });
    }

    async handleInput() {
      const query = this.input.value.trim();
      this.activeIndex = -1;

      if (query.length < this.config.minChars) {
        this.clearSuggestions();
        return;
      }

      try {
        // Cancelar petición anterior si existe
        if (this.lastRequest) {
          this.lastRequest.abort();
        }

        const controller = new AbortController();
        this.lastRequest = controller;

        const headers = {
          'Content-Type': 'application/json',
          ...(this.config.jwtToken && { 
            'Authorization': `Bearer ${this.config.jwtToken}` 
          })
        };

        const response = await fetch(
          `${this.config.apiUrl}?name=${encodeURIComponent(query)}`, 
          {
            headers,
            signal: controller.signal
          }
        );

        if (!response.ok) throw new Error(`Error HTTP: ${response.status}`);

        const data = await response.json();
        this.currentSuggestions = Array.isArray(data) ? data : data.data || [];
        this.renderSuggestions();

      } catch (error) {
        if (error.name !== 'AbortError') {
          console.error('Error en AutoComplete:', error);
          this.clearSuggestions();
        }
      } finally {
        this.lastRequest = null;
      }
    }

    renderSuggestions() {
      this.suggestionsDiv.innerHTML = '';

      if (!this.currentSuggestions || this.currentSuggestions.length === 0) {
        this.showEmptyMessage();
        return;
      }

      const fragment = document.createDocumentFragment();

      this.currentSuggestions.forEach((item, index) => {
        const div = document.createElement('div');
        div.className = `list-group-item list-group-item-action suggestion-item ${
        index === this.activeIndex ? 'active' : ''
      }`;
        
        // Mostrar el campo displayKey o name como fallback
        div.textContent = item[this.config.displayKey] || item.name || item.id;
        div.dataset.index = index;
        
        div.addEventListener('click', () => this.selectItem(index));
        div.addEventListener('mouseenter', () => {
          this.activeIndex = index;
          this.highlightItem(index);
        });

        fragment.appendChild(div);
      });

      this.suggestionsDiv.appendChild(fragment);
    }

    handleKeydown(e) {
      const items = this.suggestionsDiv.querySelectorAll('.suggestion-item');
      if (!items || items.length === 0) return;

      switch (e.key) {
        case 'ArrowDown':
          e.preventDefault();
          this.activeIndex = Math.min(this.activeIndex + 1, items.length - 1);
          this.highlightItem(this.activeIndex);
          break;

        case 'ArrowUp':
          e.preventDefault();
          this.activeIndex = Math.max(this.activeIndex - 1, 0);
          this.highlightItem(this.activeIndex);
          break;

        case 'Enter':
          e.preventDefault();
          if (this.activeIndex >= 0) {
            this.selectItem(this.activeIndex);
          }
          break;

        case 'Escape':
          this.clearSuggestions();
          break;

        case 'Tab':
          this.clearSuggestions();
          break;
      }
    }

    selectItem(index) {
      if (!this.currentSuggestions || !this.currentSuggestions[index]) return;

      const selected = this.currentSuggestions[index];
      
      // Actualizar input visible
      this.input.value = selected[this.config.displayKey] || selected.name || selected.id;
      
      // Actualizar input hidden si existe
      if (this.hiddenInput) {
        this.hiddenInput.value = selected[this.config.valueKey] || selected.id;
      }

      this.clearSuggestions();
      
      // Disparar evento personalizado
      const event = new CustomEvent('autocomplete-select', {
        detail: selected,
        bubbles: true
      });
      this.input.dispatchEvent(event);
    }

    highlightItem(index) {
      const items = this.suggestionsDiv.querySelectorAll('.suggestion-item');
      items.forEach((item, i) => {
        item.classList.toggle('active', i === index);
      });
      
      // Scroll automático para mantener el ítem visible
      if (items[index]) {
        items[index].scrollIntoView({
          behavior: 'smooth',
          block: 'nearest'
        });
      }
    }

    clearSuggestions() {
      this.suggestionsDiv.innerHTML = '';
      this.activeIndex = -1;
    }

    showEmptyMessage() {
      const emptyMsg = document.createElement('div');
      emptyMsg.className = 'list-group-item text-muted';
      emptyMsg.textContent = this.config.emptyMessage;
      this.suggestionsDiv.appendChild(emptyMsg);
    }

    // Helpers
    debounce(func, wait) {
      let timeout;
      return (...args) => {
        clearTimeout(timeout);
        timeout = setTimeout(() => func.apply(this, args), wait);
      };
    }

    // Métodos públicos adicionales
    destroy() {
      this.input.removeEventListener('input', this.handleInput);
      this.input.removeEventListener('keydown', this.handleKeydown);
      document.removeEventListener('click', this.handleOutsideClick);
      this.clearSuggestions();
    }
  }

  class FileUpload {
    constructor(options = {}) {
      // Configurable DOM element IDs
      this.containerId = options.containerId || "fileUploadContainer";
      this.fileInputId = options.fileInputId || "imageFile";
      this.triggerButtonId = options.triggerButtonId || "triggerFileButton"; // Botón que dispara el file input
      this.uploadButtonId = options.uploadButtonId || "uploadButton";
      this.viewButtonId = options.viewButtonId || "viewImageButton";
      this.errorMessageId = options.errorMessageId || "errorMessage";
      this.successMessageId = options.successMessageId || "successMessage";
      this.helpTextId = options.helpTextId || "helpText";
      this.labelElementId = options.labelElementId || null;
      this.fileNameDisplayId = options.fileNameDisplayId || "fileNameDisplay"; // Para mostrar el nombre del archivo
      
      // Component configuration
      this.label = options.label || "Seleccionar imagen";
      this.acceptedFormats = options.acceptedFormats || ["jpg", "jpeg", "png"];
      this.maxSizeMB = options.maxSizeMB || 2;
      this.baseURL = options.baseURL || "";
      this.url = this.baseURL + "/" + options.url || "/api/upload";
      this.fileKey = options.fileKey || "file";
      this.extraParams = options.extraParams || {};
      this.jwt = options.jwt || "";
      this.triggerButtonText = options.triggerButtonText || "Seleccionar archivo";
      this.triggerButtonIcon = options.triggerButtonIcon || "fa-folder-open";
      
      // Callbacks
      this.onSuccess = options.onSuccess || ((response) => console.log("Upload success:", response));
      this.onError = options.onError || ((error) => console.error("Upload error:", error));
      this.onViewClick = options.onViewClick || (() => {
        console.log("View button clicked");
      });
      
      this.file = null;
      this.isLoading = false;
      
      this.initElements();
      this.setupEventListeners();
      this.updateUI();
    }
    
    initElements() {
      // Get all DOM elements by configurable IDs
      this.container = document.getElementById(this.containerId);
      this.fileInput = document.getElementById(this.fileInputId);
      this.triggerButton = document.getElementById(this.triggerButtonId);
      this.uploadButton = document.getElementById(this.uploadButtonId);
      this.viewButton = document.getElementById(this.viewButtonId);
      this.errorMessage = document.getElementById(this.errorMessageId);
      this.successMessage = document.getElementById(this.successMessageId);
      this.helpText = document.getElementById(this.helpTextId);
      this.fileNameDisplay = document.getElementById(this.fileNameDisplayId);
      
      // Get label element (either by ID or as first label in container)
      this.labelElement = this.labelElementId 
        ? document.getElementById(this.labelElementId)
        : this.container.querySelector('label');
      
      // Update initial values
      if (this.labelElement) {
        this.labelElement.textContent = this.label;
      }
      
      // Configurar input file (oculto)
      this.fileInput.style.display = 'none';
      this.fileInput.accept = this.acceptedFormats.map(f => `.${f}`).join(',');
      
      // Configurar texto de ayuda
      if (this.helpText) {
        this.helpText.textContent = 
          `Formatos aceptados: ${this.acceptedFormats.join(", ").toUpperCase()} (Máx. ${this.maxSizeMB}MB)`;
      }
      
      // Configurar botón trigger si no tiene icono/texto personalizado
      if (this.triggerButton && this.triggerButtonText) {
        const existingIcon = this.triggerButton.querySelector('i');
        if (!existingIcon && this.triggerButtonIcon) {
          this.triggerButton.innerHTML = `<i class="fa ${this.triggerButtonIcon} me-2"></i>${this.triggerButtonText}`;
        } else if (this.triggerButton.textContent.trim() === '') {
          this.triggerButton.textContent = this.triggerButtonText;
        }
      }
    }
    
    setupEventListeners() {
      // Trigger button abre el selector de archivos
      if (this.triggerButton) {
        this.triggerButton.addEventListener('click', () => {
          this.fileInput.click();
        });
      }
      
      this.fileInput.addEventListener('change', this.handleFileChange.bind(this));
      this.uploadButton.addEventListener('click', this.uploadFile.bind(this));
      this.viewButton.addEventListener('click', () => {
        this.onViewClick(this.file, document.getElementById(this.fileNameDisplayId)?.dataset.imageUrl);
      });
    }
    
    handleFileChange(event) {
      const selectedFile = event.target.files[0];
      if (!selectedFile) return;

      // Validate format
      const fileExt = selectedFile.name.split('.').pop().toLowerCase();
      if (!this.acceptedFormats.includes(fileExt)) {
        this.showError(`Formato no válido. Use: ${this.acceptedFormats.join(", ").toUpperCase()}`);
        this.fileInput.value = ''; // Limpiar input
        return;
      }

      // Validate size
      if (selectedFile.size > this.maxSizeMB * 1024 * 1024) {
        this.showError(`El archivo excede el tamaño máximo de ${this.maxSizeMB}MB`);
        this.fileInput.value = ''; // Limpiar input
        return;
      }

      this.clearMessages();
      this.file = selectedFile;
      
      // Mostrar nombre del archivo seleccionado
      if (this.fileNameDisplay) {
        this.fileNameDisplay.textContent = `📎 ${selectedFile.name}`;
        this.fileNameDisplay.style.color = '#28a745';
        this.fileNameDisplay.dataset.imageUrl = '';
      }
      
      this.updateUI();
    }
    
    async uploadFile() {
      if (!this.file) {
        this.showError("Por favor seleccione un archivo");
        return;
      }

      this.isLoading = true;
      this.clearMessages();
      this.updateUI();

      const formData = new FormData();
      formData.append(this.fileKey, this.file);

      // Add extra parameters
      Object.keys(this.extraParams).forEach(key => {
        formData.append(key, this.extraParams[key]);
      });

      try {
        const headers = {};
        if (this.jwt) {
          headers["Authorization"] = `Bearer ${this.jwt}`;
        }
        
        const response = await fetch(this.url, {
          method: "POST",
          headers: headers,
          body: formData, 
          mode: "cors",
          credentials: "include"
        });

        const data = await response.json();
        console.log(data);
        
        if (!response.ok) {
          throw new Error(data.message || "Error al subir el archivo");
        }

        this.showSuccess("Archivo subido correctamente");
        
        // Guardar URL en el display si existe
        if (this.fileNameDisplay && data.image_url) {
          this.fileNameDisplay.dataset.imageUrl = data.image_url;
        }
        
        this.onSuccess(data);
      } catch (error) {
        this.showError(error.message);
        this.onError(error);
      } finally {
        this.isLoading = false;
        this.updateUI();
      }
    }
    
    showError(message) {
      if (this.errorMessage) {
        this.errorMessage.textContent = message;
        this.errorMessage.style.color = '#dc3545';
      }
      if (this.successMessage) {
        this.successMessage.textContent = "";
      }
    }
    
    showSuccess(message) {
      if (this.successMessage) {
        this.successMessage.textContent = message;
        this.successMessage.style.color = '#28a745';
      }
      if (this.errorMessage) {
        this.errorMessage.textContent = "";
      }
    }
    
    clearMessages() {
      if (this.errorMessage) this.errorMessage.textContent = "";
      if (this.successMessage) this.successMessage.textContent = "";
    }
    
    updateUI() {
      // Update buttons state
      if (this.uploadButton) {
        this.uploadButton.disabled = this.isLoading || !this.file;
      }
      if (this.viewButton) {
        this.viewButton.disabled = this.isLoading || (!this.file && !this.fileNameDisplay?.dataset.imageUrl);
      }
      if (this.triggerButton) {
        this.triggerButton.disabled = this.isLoading;
      }
      
      // Update upload button text and icon
      if (this.uploadButton) {
        const uploadIcon = this.uploadButton.querySelector('i');
        const uploadText = this.uploadButton.childNodes[2];
        
        if (this.isLoading) {
          if (uploadIcon) uploadIcon.className = "fa fa-spinner spinner";
          if (uploadText) uploadText.nodeValue = " Subiendo...";
        } else {
          if (uploadIcon) uploadIcon.className = "fa fa-cloud-upload";
          if (uploadText) uploadText.nodeValue = " Subir";
        }
      }
      
      // Update input state
      if (this.fileInput) {
        this.fileInput.disabled = this.isLoading;
      }
    }
    
    // Método público para limpiar el archivo seleccionado
    clearFile() {
      this.file = null;
      this.fileInput.value = '';
      if (this.fileNameDisplay) {
        this.fileNameDisplay.textContent = '';
        this.fileNameDisplay.dataset.imageUrl = '';
      }
      this.clearMessages();
      this.updateUI();
    }
    
    // Método público para establecer URL de imagen existente
    setExistingImageUrl(url) {
      if (this.fileNameDisplay) {
        this.fileNameDisplay.dataset.imageUrl = url;
        this.fileNameDisplay.textContent = `🖼️ Imagen existente`;
        this.fileNameDisplay.style.color = '#17a2b8';
      }
      this.updateUI();
    }
  }

  window.AutoComplete = AutoComplete;
  window.FileUpload = FileUpload;

  document.addEventListener('DOMContentLoaded', function() {
    const sidebarToggle = document.getElementById('sidebarToggle');
    const sidebar = document.querySelector('.sidebar');
    
    let isCollapsed = localStorage.getItem('sidebarCollapsed') === 'true';
    
    function updateSidebarState() {
      if (window.innerWidth <= 992) {
        sidebar.classList.add('collapsed');
      } else {
        sidebar.classList.toggle('collapsed', isCollapsed);
      }
    }
    
    updateSidebarState();
    
    sidebarToggle.addEventListener('click', function() {
      if (window.innerWidth <= 992) {
        sidebar.classList.toggle('collapsed');
      } else {
        isCollapsed = !isCollapsed;
        localStorage.setItem('sidebarCollapsed', isCollapsed);
        sidebar.classList.toggle('collapsed');
      }
    });
    
    document.querySelectorAll('.sidebar .nav-link').forEach(link => {
      link.addEventListener('click', function() {
        if (window.innerWidth <= 992) {
          sidebar.classList.add('collapsed');
        }
      });
    });
    
    window.addEventListener('resize', function() {
      updateSidebarState();
    });
  });

})();
